import{_ as a,o,c as t,ai as i}from"./chunks/framework.CsYGeNYI.js";const g=JSON.parse('{"title":"Discovery and Transports","description":"","frontmatter":{"summary":"Node discovery and transports (Bonjour, Tailscale, SSH) for finding the gateway","read_when":["Implementing or changing Bonjour discovery/advertising","Adjusting remote connection modes (direct vs SSH)","Designing node discovery + pairing for remote nodes"],"title":"Discovery and Transports"},"headers":[],"relativePath":"gateway/discovery.md","filePath":"gateway/discovery.md","lastUpdated":1771906665000}'),n={name:"gateway/discovery.md"};function s(r,e,l,d,c,h){return o(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="discovery-transports" tabindex="-1"><a class="header-anchor" href="#discovery-transports">#</a> Discovery &amp; transports</h1><p>OpenSoul has two distinct problems that look similar on the surface:</p><ol><li><strong>Operator remote control</strong>: the macOS menu bar app controlling a gateway running elsewhere.</li><li><strong>Node pairing</strong>: iOS/Android (and future nodes) finding a gateway and pairing securely.</li></ol><p>The design goal is to keep all network discovery/advertising in the <strong>Node Gateway</strong> (<code>opensoul gateway</code>) and keep clients (mac app, iOS) as consumers.</p><h2 id="terms" tabindex="-1"><a class="header-anchor" href="#terms">#</a> Terms</h2><ul><li><strong>Gateway</strong>: a single long-running gateway process that owns state (sessions, pairing, node registry) and runs channels. Most setups use one per host; isolated multi-gateway setups are possible.</li><li><strong>Gateway WS (control plane)</strong>: the WebSocket endpoint on <code>127.0.0.1:18789</code> by default; can be bound to LAN/tailnet via <code>gateway.bind</code>.</li><li><strong>Direct WS transport</strong>: a LAN/tailnet-facing Gateway WS endpoint (no SSH).</li><li><strong>SSH transport (fallback)</strong>: remote control by forwarding <code>127.0.0.1:18789</code> over SSH.</li><li><strong>Legacy TCP bridge (deprecated/removed)</strong>: older node transport (see <a href="/docs/gateway/bridge-protocol">Bridge protocol</a>); no longer advertised for discovery.</li></ul><p>Protocol details:</p><ul><li><a href="/docs/gateway/protocol">Gateway protocol</a></li><li><a href="/docs/gateway/bridge-protocol">Bridge protocol (legacy)</a></li></ul><h2 id="why-we-keep-both-direct-and-ssh" tabindex="-1"><a class="header-anchor" href="#why-we-keep-both-direct-and-ssh">#</a> Why we keep both “direct” and SSH</h2><ul><li><strong>Direct WS</strong> is the best UX on the same network and within a tailnet: <ul><li>auto-discovery on LAN via Bonjour</li><li>pairing tokens + ACLs owned by the gateway</li><li>no shell access required; protocol surface can stay tight and auditable</li></ul></li><li><strong>SSH</strong> remains the universal fallback: <ul><li>works anywhere you have SSH access (even across unrelated networks)</li><li>survives multicast/mDNS issues</li><li>requires no new inbound ports besides SSH</li></ul></li></ul><h2 id="discovery-inputs-how-clients-learn-where-the-gateway-is" tabindex="-1"><a class="header-anchor" href="#discovery-inputs-how-clients-learn-where-the-gateway-is">#</a> Discovery inputs (how clients learn where the gateway is)</h2><h3 id="_1-bonjour-mdns-lan-only" tabindex="-1"><a class="header-anchor" href="#_1-bonjour-mdns-lan-only">#</a> 1) Bonjour / mDNS (LAN only)</h3><p>Bonjour is best-effort and does not cross networks. It is only used for “same LAN” convenience.</p><p>Target direction:</p><ul><li>The <strong>gateway</strong> advertises its WS endpoint via Bonjour.</li><li>Clients browse and show a “pick a gateway” list, then store the chosen endpoint.</li></ul><p>Troubleshooting and beacon details: <a href="/docs/gateway/bonjour">Bonjour</a>.</p><h4 id="service-beacon-details" tabindex="-1"><a class="header-anchor" href="#service-beacon-details">#</a> Service beacon details</h4><ul><li>Service types: <ul><li><code>_opensoul-gw._tcp</code> (gateway transport beacon)</li></ul></li><li>TXT keys (non-secret): <ul><li><code>role=gateway</code></li><li><code>lanHost=&lt;hostname&gt;.local</code></li><li><code>sshPort=22</code> (or whatever is advertised)</li><li><code>gatewayPort=18789</code> (Gateway WS + HTTP)</li><li><code>gatewayTls=1</code> (only when TLS is enabled)</li><li><code>gatewayTlsSha256=&lt;sha256&gt;</code> (only when TLS is enabled and fingerprint is available)</li><li><code>canvasPort=18793</code> (default canvas host port; serves <code>/__opensoul__/canvas/</code>)</li><li><code>cliPath=&lt;path&gt;</code> (optional; absolute path to a runnable <code>opensoul</code> entrypoint or binary)</li><li><code>tailnetDns=&lt;magicdns&gt;</code> (optional hint; auto-detected when Tailscale is available)</li></ul></li></ul><p>Disable/override:</p><ul><li><code>OPENSOUL_DISABLE_BONJOUR=1</code> disables advertising.</li><li><code>gateway.bind</code> in <code>~/.opensoul/opensoul.json</code> controls the Gateway bind mode.</li><li><code>OPENSOUL_SSH_PORT</code> overrides the SSH port advertised in TXT (defaults to 22).</li><li><code>OPENSOUL_TAILNET_DNS</code> publishes a <code>tailnetDns</code> hint (MagicDNS).</li><li><code>OPENSOUL_CLI_PATH</code> overrides the advertised CLI path.</li></ul><h3 id="_2-tailnet-cross-network" tabindex="-1"><a class="header-anchor" href="#_2-tailnet-cross-network">#</a> 2) Tailnet (cross-network)</h3><p>For London/Vienna style setups, Bonjour won’t help. The recommended “direct” target is:</p><ul><li>Tailscale MagicDNS name (preferred) or a stable tailnet IP.</li></ul><p>If the gateway can detect it is running under Tailscale, it publishes <code>tailnetDns</code> as an optional hint for clients (including wide-area beacons).</p><h3 id="_3-manual-ssh-target" tabindex="-1"><a class="header-anchor" href="#_3-manual-ssh-target">#</a> 3) Manual / SSH target</h3><p>When there is no direct route (or direct is disabled), clients can always connect via SSH by forwarding the loopback gateway port.</p><p>See <a href="/docs/gateway/remote">Remote access</a>.</p><h2 id="transport-selection-client-policy" tabindex="-1"><a class="header-anchor" href="#transport-selection-client-policy">#</a> Transport selection (client policy)</h2><p>Recommended client behavior:</p><ol><li>If a paired direct endpoint is configured and reachable, use it.</li><li>Else, if Bonjour finds a gateway on LAN, offer a one-tap “Use this gateway” choice and save it as the direct endpoint.</li><li>Else, if a tailnet DNS/IP is configured, try direct.</li><li>Else, fall back to SSH.</li></ol><h2 id="pairing-auth-direct-transport" tabindex="-1"><a class="header-anchor" href="#pairing-auth-direct-transport">#</a> Pairing + auth (direct transport)</h2><p>The gateway is the source of truth for node/client admission.</p><ul><li>Pairing requests are created/approved/rejected in the gateway (see <a href="/docs/gateway/pairing">Gateway pairing</a>).</li><li>The gateway enforces: <ul><li>auth (token / keypair)</li><li>scopes/ACLs (the gateway is not a raw proxy to every method)</li><li>rate limits</li></ul></li></ul><h2 id="responsibilities-by-component" tabindex="-1"><a class="header-anchor" href="#responsibilities-by-component">#</a> Responsibilities by component</h2><ul><li><strong>Gateway</strong>: advertises discovery beacons, owns pairing decisions, and hosts the WS endpoint.</li><li><strong>macOS app</strong>: helps you pick a gateway, shows pairing prompts, and uses SSH only as a fallback.</li><li><strong>iOS/Android nodes</strong>: browse Bonjour as a convenience and connect to the paired Gateway WS.</li></ul>',35)])])}const u=a(n,[["render",s]]);export{g as __pageData,u as default};
